-/// Output events as JSON.
-fn output_json(events: &[AuditEventOutput]) -> Result<()> {
-    for event in events {
-        let json = serde_json::to_string(event).context("failed to serialize event")?;
-        println!("{json}");
-    }
-    Ok(())
-}
