-    // Base manifest template with placeholder hash (no signatures yet)
-    let manifest_template = format!(
-        r#"[manifest]
-format = "fcp-connector-manifest"
-schema_version = "2.1"
-min_mesh_version = "2.0.0"
-min_protocol = "fcp2-sym/2.0"
-protocol_features = []
