-    println!();
-
-    // Object IDs (if mirrored)
-    if let Some(ref mid) = output.manifest_object_id {
-        println!("  {cyan}Manifest Object:{reset} {mid}");
-    }
-    if let Some(ref bid) = output.binary_object_id {
